const PLUGIN_CATEGORIES = [1, 2, 3, 4];

// ============ 插件属性类型定义 ============
// key: 内部标识；label: 编辑器下拉显示文本；field: 对应 stats 字段；desc: 计算器 tooltip
// additive: 同类型属性累加（加算），independent: 独立乘区（乘算）
const PLUGIN_ATTRIBUTE_TYPES = [
  { key: 'weaponShootDmg',   label: '武器射击伤害',          field: 'damage',       desc: '武器基础射击伤害提升' },
  { key: 'dmgUp',            label: '增伤提升',              field: 'damage',       desc: '伤害提升（加算乘区）' },
  { key: 'extraDmg',         label: '额外的伤害',            field: 'damage',       desc: '额外伤害提升（加算乘区）' },
  { key: 'weaponSkillDmg',   label: '武器技能伤害提升',      field: 'damage',       desc: '武器技能伤害提升（加算乘区）' },
  { key: 'dmgUp2',           label: '伤害提升',              field: 'damage',       desc: '伤害提升（加算乘区）' },
];

// 根据类型 key 获取定义
function getPluginAttrType(typeKey) {
  return PLUGIN_ATTRIBUTE_TYPES.find(t => t.key === typeKey) || null;
}

